Javascript.validate:
var val = Services.getValue(ApportionAmnt.dataBinding);
var err = validateCurrencyValue(val, 999999999.99);
if( null == err )
{	Services.setValue(ApportionAmnt.dataBinding, WPU.formatToTwoDP(val));
}
return err;

