function DefaultCurrency600() {}
DefaultCurrency600.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency600.tabIndex = -1;
DefaultCurrency600.maxLength = 1;
DefaultCurrency600.isReadOnly = function(){return true;}
DefaultCurrency600.isTemporary = function(){return true;}
DefaultCurrency600.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency600.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
